import pika

# Connection parameters
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
RABBITMQ_VHOST = '/'
RABBITMQ_USERNAME = 'guest'
RABBITMQ_PASSWORD = 'guest'

connection = pika.BlockingConnection(
    pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT,
                              virtual_host=RABBITMQ_VHOST,
                              credentials=pika.PlainCredentials(RABBITMQ_USERNAME,
                                                                RABBITMQ_PASSWORD))
)

channel = connection.channel()

# Declare exchange and queue
exchange_name = 'job_exchange'
queue_name = 'job_queue'

channel.exchange_declare(exchange=exchange_name, type='direct')

channel.queue_declare(queue=queue_name)
channel.queue_bind(exchange=exchange_name,
                   queue=queue_name)

def callback(ch, method, properties, msg):
    try:
        result = subprocess.run(msg.body, shell=True, check=True)
        print(f'Job {msg.delivery_tag} completed successfully with exit code {result.returncode}')
    except subprocess.CalledProcessError as e:
        print(f'Job {msg.delivery_tag} failed with exit code {e.returncode}')

# Consume messages from the queue
channel.basic_consume(queue=queue_name, on_message_callback=callback,
                      no_ack=False)

print('Starting job consumer...')

try:
    channel.start_consuming()
except KeyboardInterrupt as e:
    print(e)